def faq_json(section_html):
    qs=[]
    for m in re.finditer(r'<h3>(.*?)</h3><p>(.*?)</p>', section_html, re.S):
        qs.append({'@type':'Question','name':re.sub('<.*?>','',m.group(1)),'acceptedAnswer':{'@type':'Answer','text':re.sub('<.*?>','',m.group(2))}})
    return qs

